import { ref, computed, watch, toValue, type ComputedRef, type MaybeRefOrGetter, type Ref } from 'vue'
import { formatDate } from '@/lib/date'

type DatePickerEmit = ((event: 'open') => void)
    & ((event: 'close') => void)
    & ((event: 'change', value: Date | null) => void)
    & ((event: 'update:modelValue', value: Date | null) => void)

export interface UseDatePickerOptions {
    modelValue?: MaybeRefOrGetter<Date | null>
    displayFormat?: MaybeRefOrGetter<string>
    disabled?: MaybeRefOrGetter<boolean>
    readonly?: MaybeRefOrGetter<boolean>
    openProp?: MaybeRefOrGetter<boolean | undefined>
    emitUpdateOpen?: (value: boolean) => void
    emit: DatePickerEmit
}

export interface UseDatePickerReturn {
    open: Ref<boolean>
    displayValue: Ref<Date | null>
    formattedDisplay: ComputedRef<string>
    handlePanelUpdate: (value: Date | null) => void
    handlePanelConfirm: (value: Date | null) => void
    handlePanelClear: () => void
    handleClearClick: (event: Event) => void
    handleTriggerKeydown: (event: KeyboardEvent) => void
}

export function useDatePicker(options: UseDatePickerOptions): UseDatePickerReturn {
    const internalOpen = ref(false)

    const open = computed<boolean>({
        get: () => {
            const controlled = toValue(options.openProp)
            return controlled !== undefined ? controlled : internalOpen.value
        },
        set: (val) => {
            const controlled = toValue(options.openProp)
            if (controlled === undefined) {
                internalOpen.value = val
            }
            options.emitUpdateOpen?.(val)
        },
    })

    const displayValue = ref<Date | null>(toValue(options.modelValue) ?? null)

    let suppressCloseChange = false

    watch(open, (isOpen) => {
        if (isOpen) {
            suppressCloseChange = false
            options.emit('open')
        } else {
            options.emit('close')
            if (suppressCloseChange) {
                suppressCloseChange = false
                return
            }
            const currentModel = toValue(options.modelValue) ?? null
            if (displayValue.value?.getTime() !== currentModel?.getTime()) {
                options.emit('change', displayValue.value)
            }
        }
    })

    if (options.openProp !== undefined) {
        watch(() => toValue(options.openProp), (val) => {
            if (val !== undefined) internalOpen.value = val
        }, { immediate: true })
    }

    watch(() => toValue(options.modelValue), (value) => {
        displayValue.value = value ?? null
    })

    const formattedDisplay = computed(() => {
        const value = toValue(options.modelValue)
        if (!value) return ''
        return formatDate(value, toValue(options.displayFormat) ?? 'YYYY-MM-DD')
    })

    function handlePanelUpdate(value: Date | null) {
        displayValue.value = value
        options.emit('update:modelValue', value)
    }

    function handlePanelConfirm(value: Date | null) {
        displayValue.value = value
        options.emit('update:modelValue', value)
        options.emit('change', value)
        suppressCloseChange = true
        open.value = false
    }

    function handlePanelClear() {
        displayValue.value = null
        options.emit('update:modelValue', null)
        options.emit('change', null)
    }

    function handleClearClick(event: Event) {
        event.stopPropagation()
        displayValue.value = null
        options.emit('update:modelValue', null)
        options.emit('change', null)
    }

    function handleTriggerKeydown(event: KeyboardEvent) {
        if (toValue(options.disabled) || toValue(options.readonly)) return
        if ((event.key === 'Enter' || event.key === ' ') && !open.value) {
            event.preventDefault()
            open.value = true
        }
    }

    return {
        open,
        displayValue,
        formattedDisplay,
        handlePanelUpdate,
        handlePanelConfirm,
        handlePanelClear,
        handleClearClick,
        handleTriggerKeydown,
    }
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

